    // (r,g,b,a)\nattribute vec2 in_TextureCoord;              // (u,v)\n\nvarying vec2 v_vTexcoord;\nvarying vec4 v_vColour;\n\nvoid main()\n{\n    vec4 object_space_pos = vec4( in_Position.x, in_Position.y, in_Position.z, 1.0);\n    gl_Position = gm_Matrices[MATRIX_WORLD_VIEW_PROJECTION] * object_space_pos;\n    \n    v_vColour = in_Colour;\n    v_vTexcoord = in_TextureCoord;\n}\n",
_C3:"precision mediump float;\n#define LOWPREC lowp\n// Uniforms look like they're shared between vertex and fragment shaders in GLSL, so we have to be careful to avoid name clashes\n\nuniform sampler2D gm_BaseTexture;\n\nuniform bool gm_PS_FogEnabled;\nuniform vec4 gm_FogColour;\nuniform bool gm_AlphaTestEnabled;\nuniform float gm_AlphaRefValue;\n\nvoid DoAlphaTest(vec4 SrcColour)\n{\n	if (gm_AlphaTestEnabled)\n	{\n		if (SrcColour.a <= gm_AlphaRefValue)\n		{\n			discard;\n		}\n	}\n}\n\nvoid DoFog(inout vec4 SrcColour, float fogval)\n{\n	if (gm_PS_FogEnabled)\n	{\n		SrcColour = mix(SrcColour, gm_FogColour, clamp(fogval, 0.0, 1.0)); \n	}\n}\n\n#define _YY_GLSLES_ 1\n//\n// Simple passthrough fragment shader\n//\nvarying vec2 v_vTexcoord;\nvarying vec4 v_vColour;\n\nuniform vec4 lim;\nuniform float u_time;\nuniform vec2 texel;\nuniform float seed;\n\nfloat rng(vec2 uv)\n{\n    return fract( sin(uv.x*100.+uv.y*12398.)*12351. );\n}\n\nvec2 random2( vec2 p ) {\n    return fract(sin(vec2(dot(p,vec2(127.1,311.7)),dot(p,vec2(269.5,183.3))))*43758.5453);\n}\n\nvec3 voronoi( in vec2 x,float vein ) {\n    vec2 n = floor(x);\n    vec2 f = fract(x);\n    float ut = sin( u_time )*0.05;\n\n    // first pass: regular voronoi\n    vec2 mg, mr;\n    float md = 8.0;\n    for (int j= -1; j <= 1; j++) {\n        for (int i= -1; i <= 1; i++) {\n            vec2 g = vec2(float(i),float(j));\n            vec2 o = random2( n + g );\n            o = 0.5 + 0.5*sin( ut+6.2831*o );\n\n            vec2 r = g + o - f;\n            float d = dot(r,r);\n\n            if( d<md ) {\n                md = d;\n                mr = r;\n                mg = g;\n            }\n        }\n    }\n\n    // second pass: distance to borders\n    md = 8.0;\n    for (int j= -2; j <= 2; j++) {\n        for (int i= -2; i <= 2; i++) {\n            vec2 g = mg + vec2(float(i),float(j));\n            vec2 o = random2( n + g );\n            o = 0.5 + 0.5*sin( ut+6.2831*o );\n\n            vec2 r = g + o - f;\n\n            if ( dot(mr-r,mr-r)>0.0001 ) {\n                md = min(md, dot( vein*(mr+r), normalize(r-mr) ));\n            }\n        }\n    }\n    return vec3(md, mr);\n}\n\nfloat noise(vec2 uv)\n{\n    vec2 gv = smoothstep( 0.,1.,fract(uv) );\n    vec2 id = floor(uv);\n\n    float bl = rng(id);\n    float br = rng(id+vec2(1,0));\n    float b = mix(bl,br,gv.x);\n\n    float tl = rng(id+vec2(0,1));\n    float tr = rng(id+vec2(1,1));\n    float t = mix(tl,tr,gv.x);\n\n    float c = mix(b,t,gv.y);\n    return c;\n}\n\nfloat noise3(vec2 uv)\n{\n    //uv*=2.;\n    float c = noise(uv*4.);\n    c+=noise(uv*8.)*.5;\n    c+=noise(uv*16.)*.25;\n    c+=noise(uv*32.)*.125;\n    c+=noise(uv*64.)*.0625;\n\n    c = step( (sin(u_time*.5)+1.)*.2 + 1.,c);\n    return c;\n\n}\n\nvoid main() {\n    //vec2 uv = vec2( (v_vTexcoord.x - lim[0]) / (lim[2] - lim[0]) , (v_vTexcoord.y - lim[1]) / (lim[3] - lim[1]) );\n	vec2 uv = v_vTexcoord;\n	uv = floor(uv*100.)*1./100.;\n	uv.y = 1.-uv.y;\n\n    vec3 color = vec3(0.);\n    vec3 veins = vec3(0.);\n    vec3 sveins = vec3(0.);\n\n    float s = 10.;\n\n    vec2 st = uv;\n\n    // Scale\n    st *= s;\n	st += seed;\n\n   //veins\n    veins = voronoi(st*.3+noise(st)*vec2(.4,.5),.4);\n\n    //mask\n    sveins = vec3( 1.-noise3(st)  );\n\n    //small veins\n    sveins = voronoi(st*1.,.6 );\n\n    //Borders\n\n    float mask = 0.;\n\n    vec3 t_sv = mix( vec3(0.6745, 0.0902, 0.0902), 1.0+color, smoothstep( 0.005, 0.1, sveins.x ) ) \n    + noise(st*.3)*1.2\n    ;\n\n    vec3 t_v = mix( vec3(0.6745, 0.0902, 0.0902), 1.+color, smoothstep( 0.02, 0.1, veins.x ) ) \n    + noise(st*4.)*((sin(u_time*1.5)+1.)*.2+.6)*.1\n    ;\n\n    color = t_sv * t_v ;\n	\n	color += uv.y;\n	\n	color.r = clamp(0.,1.,color.r);\n	color.g = clamp(0.,1.,color.g);\n	color.b = clamp(0.,1.,color.b);\n	\n	//red outline\n	vec4 tex = texture2D(gm_BaseTexture,v_vTexcoord);\n	\n	if( tex.a==0. )\n	{\n	\n		float border = 0.;\n	\n		border += texture2D(gm_BaseTexture,v_vTexcoord+vec2(texel.x,0.)).a  ;\n		border += texture2D(gm_BaseTexture,v_vTexcoord+vec2(-texel.x,0.)).a  ;\n		border += texture2D(gm_BaseTexture,v_vTexcoord+vec2(0.,texel.y)).a  ;\n		border += texture2D(gm_BaseTexture,v_vTexcoord+vec2(0.,-texel.y)).a  ;\n\n		if( border>=1. )\n		{\n			tex = vec4(0.4, 0.0196, 0.0196,1.);\n		}\n	\n	}\n	\n	\n    gl_FragColor = vec4( color,1.)*( tex +vec4( (sin(u_time)+1.)*.5*.3 ,0,0,0) );\n}\n",
