         // (r,g,b,a)\nattribute vec2 in_TextureCoord;              // (u,v)\n\nvarying vec2 v_vTexcoord;\nvarying vec4 v_vColour;\n\nvoid main()\n{\n    vec4 object_space_pos = vec4( in_Position.x, in_Position.y, in_Position.z, 1.0);\n    gl_Position = gm_Matrices[MATRIX_WORLD_VIEW_PROJECTION] * object_space_pos;\n    \n    v_vColour = in_Colour;\n    v_vTexcoord = in_TextureCoord;\n}\n",
_C3:"precision mediump float;\n#define LOWPREC lowp\n// Uniforms look like they're shared between vertex and fragment shaders in GLSL, so we have to be careful to avoid name clashes\n\nuniform sampler2D gm_BaseTexture;\n\nuniform bool gm_PS_FogEnabled;\nuniform vec4 gm_FogColour;\nuniform bool gm_AlphaTestEnabled;\nuniform float gm_AlphaRefValue;\n\nvoid DoAlphaTest(vec4 SrcColour)\n{\n	if (gm_AlphaTestEnabled)\n	{\n		if (SrcColour.a <= gm_AlphaRefValue)\n		{\n			discard;\n		}\n	}\n}\n\nvoid DoFog(inout vec4 SrcColour, float fogval)\n{\n	if (gm_PS_FogEnabled)\n	{\n		SrcColour = mix(SrcColour, gm_FogColour, clamp(fogval, 0.0, 1.0)); \n	}\n}\n\n#define _YY_GLSLES_ 1\nvarying vec2 v_vPosition;\nvarying vec2 v_vTexcoord;\nvarying vec4 v_vColour;\n\nuniform float u_time;\n\n#define MAX_DIST 1000.\n#define MAX_STEP 100.\n\nvec2 hash(vec2 p) {\n    return fract(sin(vec2(dot(p, vec2(127.1, 311.7)),dot(p, vec2(269.5, 183.3)))) * 43758.5453);\n}\n\nfloat noise2(vec2 uv){return fract(sin(uv.x*100.+uv.y*17.745)*63.1293);}\n\nfloat pnoise(vec2 uv)\n{\n    vec2 gv = smoothstep( 0.,1.,fract(uv) );\n    vec2 id = floor(uv);\n\n    float bl = noise2(id);\n    float br = noise2(id+vec2(1,0));\n    float b = mix(bl,br,gv.x);\n\n    float tl = noise2(id+vec2(0,1));\n    float tr = noise2(id+vec2(1,1));\n    float t = mix(tl,tr,gv.x);\n\n    float c = mix(b,t,gv.y);\n    return c;\n}\n\nfloat snoise(vec2 uv,float vel)\n{\n    uv.y -= u_time*vel;\n\n\n    float c = pnoise(uv*4.);\n    c+=pnoise(uv*8.)*.5;\n    c+=pnoise(uv*16.)*.25;\n    c+=pnoise(uv*32.)*.125;\n    c+=pnoise(uv*64.)*.0625;\n\n    c/=2.;\n    c = clamp(0.,1.,c);\n\n    return c;\n\n}\n\nfloat cnoise(vec2 uv)\n{\n    vec3 c = vec3(0.);\n    float t = u_time*.5+1000.;\n    float tile = 3.;\n\n\n    uv*=tile;\n    uv-=0.5;\n    // float ti = 10.;\n    // uv = floor(uv*ti)*1./ti;\n    uv *= snoise( uv*.025,0. );\n\n\n    vec2 id = floor(uv)+1.;\n    vec2 gv = fract(uv)-.5;\n\n    float minDist=100.;\n\n    for( float y=-1.;y<=1.;y++ )\n    {\n        for( float x=-1.;x<=1.;x++ )\n        {\n            vec2 offset = vec2(x,y);\n            vec2 n = hash( id+offset ) ;\n            vec2 p = offset+sin(n*t)*.5;\n\n            float d = length(gv-p)*length(gv-p);\n            c += smoothstep( 0.3,0.9,d );\n\n            if(d<minDist)\n            {\n                minDist=d;\n            }\n            \n        }\n\n    }\n\n    return minDist;\n}\n\nmat2 rotate( float m )\n{\n    float c = cos(m*.5);\n    float s = sin(m*.5);\n    \n    return mat2(c,-s,s,c);\n\n}\n\nfloat getDist(vec3 p)\n{\n    vec4 s = vec4(0,3,4,2.7);\n    \n    float sphereDist = length(p-s.xyz) - s.w - cnoise(p.xy)*.15;\n\n    sphereDist += sin(p.y*2.+u_time*.5)*cos(p.x+u_time)*.04;\n\n    //sphereDist -=  sin(p.z*cos(u_time)*.4)*cos(p.y*sin(u_time)*.4)*sin(p.x*sin(u_time)*.2);\n\n    return sphereDist;\n\n}\n\nfloat rayMarch(vec3 ro,vec3 rd)\n{\n    float dO = 0.;\n\n    for( float i=0.;i<MAX_STEP;i++ )\n    {\n        vec3 p = ro + rd*dO;\n        float dS=getDist(p);\n\n        dO += dS;\n        if(dO>MAX_DIST || abs(dS)<0.01){break;}\n    }\n\n    return dO;\n}\n\nvec3 getNormal(vec3 p)\n{\n    float d = getDist(p);\n    vec2 e = vec2(.001,0.);\n    vec3 n = d-vec3\n    (\n        getDist(p-e.xyy),\n        getDist(p-e.yxy),\n        getDist(p-e.yyx)\n    )\n    ;\n\n    return normalize(n);\n}\n\nfloat getLight(vec3 p)\n{\n    vec3 lightPos = vec3(0,100, (sin(u_time)+1.)*-50. -50. );\n    vec3 l = normalize(lightPos-p);\n    vec3 n = getNormal(p);\n\n    float dif = clamp( dot( n,l ) ,0.,1. ); \n\n    return dif;\n\n}\n\n\n\n#define pi 3.1416\n\n\nvoid main()\n{\n    \n    vec2 uv = v_vTexcoord*2.-1.;\n	//uv = floor(uv*100.)*1./100.;\n	uv.y=-uv.y;\n\n    vec3 col = vec3(0.);\n    vec3 ro = vec3(0,3,0); //camera\n\n    vec3 rd = normalize(vec3(uv,1)); //scene\n\n    float d = rayMarch(ro,rd);\n   \n    vec3 baseColor = vec3(0);\n    vec3 edgeColor = vec3(0.7255, 0.1529, 0.8667);\n    float baseAlpha = 0.;\n    float edgeAlpha = 0.;\n\n    if(d<MAX_DIST)\n    {\n        vec3 p = ro + rd*d ;\n\n        vec3 n = getNormal(p);\n        \n        edgeAlpha = max( 0.,( dot(rd, n)+.3 )*2.  ) ;        // maior nas bordas\n        edgeAlpha = smoothstep(.05,.5,edgeAlpha);\n\n        vec3 dif = vec3(getLight(p)); \n\n        baseAlpha = cnoise(p.xy);\n\n        baseColor = mix( vec3(0.7725, 0.251, 0.6157),vec3(0.1843, 0.0118, 0.2275),baseAlpha*dif);\n        baseColor = vec3(0.7725, 0.251, 0.6157)*dif;\n\n        baseColor = baseColor*(1.-edgeAlpha) + edgeColor*edgeAlpha;\n\n        baseAlpha = baseAlpha;\n\n    }\n    gl_FragColor = vec4( baseColor,(baseAlpha+edgeAlpha)*smoothstep(.1,.5,length(uv) ) );\n\n}\n",
